INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5e95356b-e091-45fd-baab-10b9302b101c', $q$Free course auditing$q$, $q$Most courses can be audited at no cost, giving access to video lectures and, on many courses, reading materials without a graded track.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5e95356b-e091-45fd-baab-10b9302b101c', $q$Verified certificates$q$, $q$Paid certificates carry the issuing university or company's name and can be shared on LinkedIn or resumes as proof of completion.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5e95356b-e091-45fd-baab-10b9302b101c', $q$MicroMasters programs$q$, $q$Graduate-level course sequences that can count toward credit in a full master's degree at partner universities.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5e95356b-e091-45fd-baab-10b9302b101c', $q$Professional Certificates$q$, $q$Multi-course, job-focused credential tracks in fields like data science, cybersecurity, and project management.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5e95356b-e091-45fd-baab-10b9302b101c', $q$Open edX platform$q$, $q$The underlying learning management system is open source and used independently by universities and companies to run their own portals.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5e95356b-e091-45fd-baab-10b9302b101c', $q$University and industry partners$q$, $q$Course content is produced by named institutions such as Harvard, MIT, IBM, and Google rather than independent instructors.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5e95356b-e091-45fd-baab-10b9302b101c', $q$Mobile learning$q$, $q$iOS and Android apps let learners watch lectures and track progress offline or on the go.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5e95356b-e091-45fd-baab-10b9302b101c', $q$Discussion forums$q$, $q$Course-specific forums allow learners to ask questions and interact with peers and, in some courses, teaching staff.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5e95356b-e091-45fd-baab-10b9302b101c', $q$Genuine content from well-known universities and companies, not independent instructors$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5e95356b-e091-45fd-baab-10b9302b101c', $q$Free audit track available on the large majority of courses$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5e95356b-e091-45fd-baab-10b9302b101c', $q$Stackable credentials (certificates, MicroMasters, MicroBachelors) that can lead toward formal degree credit$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5e95356b-e091-45fd-baab-10b9302b101c', $q$Open-source Open edX platform available for institutions to self-host$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5e95356b-e091-45fd-baab-10b9302b101c', $q$No flat-rate subscription for unlimited access, unlike some competitors$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5e95356b-e091-45fd-baab-10b9302b101c', $q$Certificate and program pricing can be significantly higher than competing platforms$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5e95356b-e091-45fd-baab-10b9302b101c', $q$Course quality and support vary depending on the partner institution$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5e95356b-e091-45fd-baab-10b9302b101c', $q$Ongoing uncertainty tied to parent company 2U's 2024 bankruptcy restructuring$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5e95356b-e091-45fd-baab-10b9302b101c', $q$Is edX free to use?$q$, $q$Auditing most courses is free, which includes video lectures and often reading materials. A verified certificate, graded assignments, or credit-bearing programs require payment.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5e95356b-e091-45fd-baab-10b9302b101c', $q$How much does an edX verified certificate cost?$q$, $q$Verified certificates for individual courses typically range from $50 to $300 depending on the course and the issuing institution.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5e95356b-e091-45fd-baab-10b9302b101c', $q$Who owns edX?$q$, $q$edX was founded as a nonprofit by Harvard and MIT in 2012 and was acquired by 2U, Inc. for $800 million in 2021. It remains part of 2U, which restructured through Chapter 11 bankruptcy in 2024 and continues operating as a private company.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5e95356b-e091-45fd-baab-10b9302b101c', $q$What is a MicroMasters program?$q$, $q$A MicroMasters is a graduate-level sequence of courses from a specific university that can be completed for a credential and, in many cases, counted toward credit if the learner is later admitted to that university's full master's degree.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5e95356b-e091-45fd-baab-10b9302b101c', $q$Does edX offer full degrees?$q$, $q$Yes, edX partners with universities to offer select fully online bachelor's and master's degree programs, in addition to shorter certificate and MicroMasters credentials.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5e95356b-e091-45fd-baab-10b9302b101c', $q$How does edX compare to Coursera?$q$, $q$Both platforms partner with universities and companies, but Coursera offers a flat-rate Coursera Plus subscription for broad access, while edX generally charges per course or per credential rather than a single subscription.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5e95356b-e091-45fd-baab-10b9302b101c', $q$Career upskilling$q$, $q$Professionals take Professional Certificate tracks in fields like data analytics, product management, or cybersecurity to build job-relevant skills.$q$, $q$Working professionals and career changers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5e95356b-e091-45fd-baab-10b9302b101c', $q$Graduate credit pathways$q$, $q$Learners complete a MicroMasters program as a lower-cost, flexible on-ramp to a partner university's full master's degree.$q$, $q$Prospective graduate students$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5e95356b-e091-45fd-baab-10b9302b101c', $q$Free self-directed learning$q$, $q$Curious learners audit university courses on topics from computer science to the humanities without paying anything.$q$, $q$Lifelong learners and students$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5e95356b-e091-45fd-baab-10b9302b101c', $q$Audit Track$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Access to video lectures","Access to most reading materials","No graded assignments","No certificate"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5e95356b-e091-45fd-baab-10b9302b101c', $q$Verified Certificate$q$, $q$$50 - $300 per course$q$, $q$One-time, per course$q$, NULL, $q$["Graded assignments and exams","Identity-verified certificate","Institution-branded credential","Unlimited course access during the run"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5e95356b-e091-45fd-baab-10b9302b101c', $q$Professional Certificate$q$, $q$$299 - $1,500+ per program$q$, $q$One-time, per program$q$, NULL, $q$["Multi-course job-focused sequence","Verified certificates for each course","Program-level completion credential"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5e95356b-e091-45fd-baab-10b9302b101c', $q$MicroMasters / MicroBachelors$q$, $q$$600 - $1,500+ per program$q$, $q$One-time, per program$q$, NULL, $q$["Graduate or undergraduate-level coursework","Potential credit toward a full degree at partner universities","Portfolio of verified certificates"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5e95356b-e091-45fd-baab-10b9302b101c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$edX is an online learning marketplace built around courses and credentials created by real universities and companies rather than independent instructors. Learners can audit thousands of courses for free or pay for a verified certificate, professional certificate program, or MicroMasters credential that can sometimes count toward a full degree.$q$, $q$Originally founded in 2012 as a nonprofit joint venture between Harvard and MIT, edX was acquired by 2U, Inc. in 2021 for $800 million and now operates as a commercial product. The underlying Open edX software remains open source and is used independently by many institutions to run their own learning platforms.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5e95356b-e091-45fd-baab-10b9302b101c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform offers self-paced and instructor-paced courses with video lectures, auto-graded quizzes, peer-graded assignments, and discussion forums. A personal dashboard tracks enrolled courses, deadlines, and earned certificates across a learner's full history on the platform.$q$, $q$Beyond individual courses, edX structures learning into stackable pathways: Professional Certificates for job-focused skill sequences, MicroMasters programs that can articulate into full master's degrees at partner universities, and MicroBachelors programs for undergraduate-level credit. Corporate and campus editions let organizations license the Open edX platform or curated content for internal training.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5e95356b-e091-45fd-baab-10b9302b101c', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$edX does not sell a flat monthly subscription for most content; instead, learners audit courses for free and pay per credential. Verified certificates for individual courses typically cost between $50 and $300, while Professional Certificate programs range roughly from $299 to $1,500 or more depending on length and institution.$q$, $q$MicroMasters programs, which bundle graduate-level coursework, generally cost between $600 and $1,500 for the complete sequence. A limited number of programs offer bundled annual access for around $199 per year. Since the 2U acquisition, free-audit access has been reduced on some courses and prices have trended higher than in edX's nonprofit era.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5e95356b-e091-45fd-baab-10b9302b101c', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5e95356b-e091-45fd-baab-10b9302b101c', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5e95356b-e091-45fd-baab-10b9302b101c', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5e95356b-e091-45fd-baab-10b9302b101c', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5e95356b-e091-45fd-baab-10b9302b101c', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e78263bf-152d-483f-a33a-9b78428215b6', $q$Shared calendaring$q$, $q$Group calendars support scheduling across teams with CalDAV sync to Apple and Android devices.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e78263bf-152d-483f-a33a-9b78428215b6', $q$InfoLog task and CRM tracking$q$, $q$A combined to-do, task, and lightweight CRM module for tracking contacts, deals, and internal work items.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e78263bf-152d-483f-a33a-9b78428215b6', $q$Integrated file management$q$, $q$A built-in file manager for document storage and sharing, with optional Collabora Online real-time co-editing.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e78263bf-152d-483f-a33a-9b78428215b6', $q$Project management$q$, $q$A dedicated Projectmanager app for planning and tracking multi-step projects alongside other groupware tools.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e78263bf-152d-483f-a33a-9b78428215b6', $q$Video conferencing integration$q$, $q$Bundled Jitsi or BigBlueButton integrations enable video meetings directly from the platform.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e78263bf-152d-483f-a33a-9b78428215b6', $q$Team chat$q$, $q$Rocket.Chat integration adds real-time messaging alongside email and calendaring.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e78263bf-152d-483f-a33a-9b78428215b6', $q$Mobile sync$q$, $q$Native sync of calendars, contacts, and tasks to iOS and Android devices via standard protocols.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e78263bf-152d-483f-a33a-9b78428215b6', $q$On-premises or cloud deployment$q$, $q$Runs on a customer's own servers or as a hosted cloud subscription in German data centers.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e78263bf-152d-483f-a33a-9b78428215b6', $q$Fully-featured Community Edition is free and open source under the GPLv2 with no artificial limits$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e78263bf-152d-483f-a33a-9b78428215b6', $q$Can be self-hosted for full data control, or run as EU-hosted cloud SaaS$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e78263bf-152d-483f-a33a-9b78428215b6', $q$Broad feature set covering email, calendar, files, projects, and helpdesk in one suite$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e78263bf-152d-483f-a33a-9b78428215b6', $q$Modular design lets organizations enable only the apps they need$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e78263bf-152d-483f-a33a-9b78428215b6', $q$User interface feels dated compared to newer SaaS collaboration tools$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e78263bf-152d-483f-a33a-9b78428215b6', $q$Self-hosting requires ongoing server administration and update management$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e78263bf-152d-483f-a33a-9b78428215b6', $q$Enterprise-tier and cloud pricing require contacting sales or reading tiered per-user documentation$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e78263bf-152d-483f-a33a-9b78428215b6', $q$Smaller ecosystem and community than larger open-source rivals like Nextcloud$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e78263bf-152d-483f-a33a-9b78428215b6', $q$Is EGroupware really free?$q$, $q$Yes. The Community Edition is released under the GPLv2 and can be downloaded and self-hosted at no cost, with the full core feature set and no artificial usage limits.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e78263bf-152d-483f-a33a-9b78428215b6', $q$What is the difference between Community Edition and EPL?$q$, $q$Community Edition (CE) is the free, open-source core. The Enterprise Professional Line (EPL) adds extra applications, administration tools, and paid vendor support, licensed per user on an annual or monthly basis.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e78263bf-152d-483f-a33a-9b78428215b6', $q$Where is EGroupware hosted for cloud customers?$q$, $q$EGroupware's cloud plans, such as eCloud and eCloud NGO, are hosted in German data centers, which appeals to organizations with EU data-residency requirements.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e78263bf-152d-483f-a33a-9b78428215b6', $q$Can EGroupware sync with my phone's calendar and contacts?$q$, $q$Yes, EGroupware supports CalDAV and CardDAV synchronization with Apple and Android devices, and also offers dedicated mobile apps.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e78263bf-152d-483f-a33a-9b78428215b6', $q$Does EGroupware support real-time document editing?$q$, $q$Yes, through an integration with Collabora Online, which enables collaborative editing of office documents directly in the browser.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e78263bf-152d-483f-a33a-9b78428215b6', $q$Who is behind EGroupware?$q$, $q$EGroupware GmbH, based in Kaiserslautern, Germany, has developed and commercially supported the open-source EGroupware project since taking over the business from Stylite AG in September 2016.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e78263bf-152d-483f-a33a-9b78428215b6', $q$European data-sovereignty-conscious collaboration$q$, $q$Organizations that must keep email, calendar, and file data on EU soil use EGroupware's self-hosted or German-hosted cloud options instead of US-based SaaS suites.$q$, $q$EU businesses and public-sector organizations$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e78263bf-152d-483f-a33a-9b78428215b6', $q$Nonprofit and school administration$q$, $q$Nonprofits and schools use discounted eCloud NGO or flat-rate eFlat School plans to run email, scheduling, and file sharing on a fixed annual budget.$q$, $q$Nonprofits and educational institutions$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e78263bf-152d-483f-a33a-9b78428215b6', $q$Self-hosted Microsoft 365 alternative$q$, $q$IT teams that already manage their own servers deploy the free Community Edition to replace proprietary groupware licensing costs.$q$, $q$IT administrators and small businesses$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e78263bf-152d-483f-a33a-9b78428215b6', $q$Community Edition$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full core groupware functionality","GPLv2 open-source license","Self-hosted","Paid hourly support available separately"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e78263bf-152d-483f-a33a-9b78428215b6', $q$eCloud$q$, $q$EUR 24.90/month$q$, $q$Monthly, 2-user minimum$q$, NULL, $q$["Hosted in German data centers","Unlimited users beyond minimum","Collabora add-on from EUR 2.25/user/month","Rocket.Chat add-on from EUR 30/month"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e78263bf-152d-483f-a33a-9b78428215b6', $q$EPL Smart$q$, $q$From EUR 62.50/month$q$, $q$Monthly, 10-user minimum$q$, NULL, $q$["Self-hosted enterprise features","Additional users at EUR 4.95/month","Vendor support at reduced hourly rate","Collabora add-on available"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e78263bf-152d-483f-a33a-9b78428215b6', $q$eFlat School$q$, $q$EUR 1,295/year$q$, $q$Annual$q$, NULL, $q$["Unlimited users","Designed for educational institutions","Optional Collabora and Rocket.Chat add-ons"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e78263bf-152d-483f-a33a-9b78428215b6', $q$Universal / eFlat$q$, $q$Custom (price on request)$q$, $q$Annual$q$, NULL, $q$["Unlimited users and concurrent connections","Large-scale or highly customized deployments","Dedicated vendor support"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e78263bf-152d-483f-a33a-9b78428215b6', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$EGroupware is an open-source groupware suite that bundles email, calendaring, contacts, file storage, project tracking, and team chat into one collaboration platform. It can be self-hosted for free under the GPLv2 or run as a paid, German-hosted cloud service.$q$, $q$The project traces back to 1996 and was relaunched as an independent GPL fork of phpGroupWare in 2003. EGroupware GmbH, headquartered in Kaiserslautern, Germany, has operated the commercial side of the project since taking over from Stylite AG in 2016.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e78263bf-152d-483f-a33a-9b78428215b6', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core modules cover shared calendars, an address book, InfoLog for task and lightweight CRM tracking, a file manager, and a project manager, all accessible from one web interface and synced to mobile devices via CalDAV and CardDAV. Real-time collaborative document editing is available through a Collabora Online integration, and video calls run through bundled Jitsi or BigBlueButton connectors.$q$, $q$The platform is modular, letting administrators enable only the applications a team needs, and it supports team chat through Rocket.Chat integration. A helpdesk and ticketing module is also available for organizations that want to manage internal or customer support requests inside the same system.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e78263bf-152d-483f-a33a-9b78428215b6', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The Community Edition is free and unlimited under the GPLv2, with paid hourly support available separately. Hosted cloud plans start at EUR 21.90 per month for nonprofits (eCloud NGO) and EUR 24.90 per month for standard use (eCloud), both with a two-user minimum, plus metered add-ons for Collabora and Rocket.Chat.$q$, $q$Self-hosted enterprise customers can license EPL Smart from EUR 62.50 per month for a ten-user minimum, with additional users at EUR 4.95 per month, while schools can choose a flat EUR 1,295 per year unlimited-user plan. The largest Universal and eFlat tiers are custom-quoted. All prices exclude VAT.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e78263bf-152d-483f-a33a-9b78428215b6', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e78263bf-152d-483f-a33a-9b78428215b6', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e78263bf-152d-483f-a33a-9b78428215b6', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e78263bf-152d-483f-a33a-9b78428215b6', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e78263bf-152d-483f-a33a-9b78428215b6', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e78263bf-152d-483f-a33a-9b78428215b6', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e78263bf-152d-483f-a33a-9b78428215b6', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7060eb6f-8b75-4dcd-b7ed-90b63b5d8986', $q$Full XMPP protocol compliance$q$, $q$Implements the complete range of core and extension XMPP protocols (XEPs) for messaging, presence, and multi-user chat.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7060eb6f-8b75-4dcd-b7ed-90b63b5d8986', $q$Native MQTT broker$q$, $q$Built-in MQTT support lets ejabberd serve as a messaging backbone for IoT devices alongside standard chat traffic.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7060eb6f-8b75-4dcd-b7ed-90b63b5d8986', $q$SIP service$q$, $q$Includes SIP proxy capabilities for voice call signaling, extending ejabberd beyond text-based messaging.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7060eb6f-8b75-4dcd-b7ed-90b63b5d8986', $q$Erlang/OTP clustering$q$, $q$Built on Erlang's distributed runtime, enabling horizontal clustering and fault tolerance across nodes.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7060eb6f-8b75-4dcd-b7ed-90b63b5d8986', $q$Mobile push notifications$q$, $q$Supports push notification gateways so mobile apps can receive messages even when not actively connected.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7060eb6f-8b75-4dcd-b7ed-90b63b5d8986', $q$Message archive management$q$, $q$Server-side message history storage and retrieval compliant with XMPP archive management extensions.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7060eb6f-8b75-4dcd-b7ed-90b63b5d8986', $q$Extensible module system$q$, $q$Custom Erlang or Lua modules can be written to add or modify server behavior for specific use cases.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7060eb6f-8b75-4dcd-b7ed-90b63b5d8986', $q$Long-Term Support releases (Business Edition)$q$, $q$Business Edition customers receive LTS releases maintained over extended periods with direct engineering support.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7060eb6f-8b75-4dcd-b7ed-90b63b5d8986', $q$Proven at extreme scale, having powered WhatsApp-influenced architecture and the Nintendo Switch's chat network$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7060eb6f-8b75-4dcd-b7ed-90b63b5d8986', $q$Fully open-source Community Edition with no licensing cost for self-hosted production use$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7060eb6f-8b75-4dcd-b7ed-90b63b5d8986', $q$Multi-protocol support (XMPP, MQTT, SIP) in a single server reduces infrastructure sprawl$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7060eb6f-8b75-4dcd-b7ed-90b63b5d8986', $q$Erlang-based architecture provides strong fault tolerance and horizontal clustering$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7060eb6f-8b75-4dcd-b7ed-90b63b5d8986', $q$Erlang is a niche language, which can raise the learning curve for teams without prior experience$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7060eb6f-8b75-4dcd-b7ed-90b63b5d8986', $q$Business Edition and Fluux cloud pricing are not published and require direct sales contact$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7060eb6f-8b75-4dcd-b7ed-90b63b5d8986', $q$XMPP as a protocol is older and less trendy than newer alternatives like Matrix for end-to-end encrypted messaging$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7060eb6f-8b75-4dcd-b7ed-90b63b5d8986', $q$Community Edition support relies on community forums and documentation rather than a formal SLA$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7060eb6f-8b75-4dcd-b7ed-90b63b5d8986', $q$Is ejabberd free to use?$q$, $q$Yes, the Community Edition is fully open source under the GPLv2 and can be self-hosted in production at no licensing cost. Paid Business Edition and Fluux cloud options add enterprise support and managed hosting.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7060eb6f-8b75-4dcd-b7ed-90b63b5d8986', $q$What protocols does ejabberd support?$q$, $q$ejabberd primarily implements XMPP for chat and presence, and also includes native MQTT broker support for IoT and SIP support for voice signaling.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7060eb6f-8b75-4dcd-b7ed-90b63b5d8986', $q$How many users can ejabberd handle?$q$, $q$A single ejabberd node can support roughly one to two million concurrently connected users, with clustering across multiple nodes enabling much larger deployments.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7060eb6f-8b75-4dcd-b7ed-90b63b5d8986', $q$Who maintains ejabberd?$q$, $q$ejabberd was started in 2002 by Alexey Shchepin and has been maintained since 2005 by the French company ProcessOne, which also offers commercial Business Edition and Fluux hosted plans.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7060eb6f-8b75-4dcd-b7ed-90b63b5d8986', $q$Is ejabberd related to WhatsApp?$q$, $q$ejabberd is widely reported to have influenced WhatsApp's original server architecture in its early years, though WhatsApp later built its own custom messaging infrastructure.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7060eb6f-8b75-4dcd-b7ed-90b63b5d8986', $q$What is the difference between ejabberd Community and Business Edition?$q$, $q$Community Edition is the free, open-source core server. Business Edition adds Long-Term Support releases, enhanced performance modules, mobile push at scale, and direct ProcessOne SLAs, priced on a custom basis.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7060eb6f-8b75-4dcd-b7ed-90b63b5d8986', $q$In-app chat for consumer apps$q$, $q$Engineering teams embed ejabberd as the real-time messaging backend for chat features in mobile and web applications.$q$, $q$Software engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7060eb6f-8b75-4dcd-b7ed-90b63b5d8986', $q$IoT device messaging$q$, $q$Companies use ejabberd's built-in MQTT broker to handle telemetry and command messaging between IoT devices and backend systems.$q$, $q$IoT platform builders$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7060eb6f-8b75-4dcd-b7ed-90b63b5d8986', $q$Large-scale gaming and telecom infrastructure$q$, $q$Gaming platforms and telecom operators deploy ejabberd clusters to handle millions of concurrent presence and messaging connections.$q$, $q$Gaming companies and telecom operators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7060eb6f-8b75-4dcd-b7ed-90b63b5d8986', $q$Community Edition$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full XMPP, MQTT, and SIP server functionality","GPLv2 open-source license","Self-hosted","Community-based support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7060eb6f-8b75-4dcd-b7ed-90b63b5d8986', $q$Business Edition$q$, $q$Custom (contact ProcessOne)$q$, $q$Annual$q$, NULL, $q$["Long-Term Support (LTS) releases","Enhanced performance modules for geo-distributed deployments","Enterprise mobile push at scale","Direct SLA with 24/7 support option"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7060eb6f-8b75-4dcd-b7ed-90b63b5d8986', $q$Fluux (managed cloud)$q$, $q$Custom (contact ProcessOne)$q$, $q$Subscription$q$, NULL, $q$["Fully managed, hosted ejabberd infrastructure","Business Edition feature set","Scalable pricing based on usage"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7060eb6f-8b75-4dcd-b7ed-90b63b5d8986', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$ejabberd is an open-source, Erlang-based server that implements the XMPP messaging protocol along with MQTT and SIP support, making it a flexible backend for chat, presence, IoT messaging, and voice signaling. It was started in 2002 by Alexey Shchepin and has been maintained since 2005 by ProcessOne, a French company founded specifically to support the project commercially.$q$, $q$The server is best known for its role in real-time messaging infrastructure at massive scale, having influenced WhatsApp's early architecture, powered a modified deployment behind Facebook's original chat feature, and today running the Nintendo Switch friend and communication network.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7060eb6f-8b75-4dcd-b7ed-90b63b5d8986', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$ejabberd supports the full range of XMPP extension protocols including multi-user chat rooms, publish-subscribe messaging, message archive management, and mobile push notifications, all built on Erlang/OTP's distributed, fault-tolerant runtime. Clustering allows a single node to handle roughly a million to two million concurrent connections, with horizontal scaling across nodes for larger deployments.$q$, $q$Beyond chat, ejabberd includes a native MQTT broker for IoT device messaging and a SIP proxy for voice signaling, letting a single server handle multiple real-time communication protocols. It can be extended with custom Erlang or Lua modules and integrates with external SQL databases for large-scale data storage.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7060eb6f-8b75-4dcd-b7ed-90b63b5d8986', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The Community Edition is free and open source under the GPLv2, with full production functionality and no licensing fees, though it does not include a formal support contract from ProcessOne.$q$, $q$The Business Edition adds enterprise features like Long-Term Support releases, enhanced performance modules, and direct SLAs with 24/7 support options, while Fluux offers a fully managed, hosted ejabberd cloud. Both are custom-priced and require contacting ProcessOne directly for a quote.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7060eb6f-8b75-4dcd-b7ed-90b63b5d8986', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7060eb6f-8b75-4dcd-b7ed-90b63b5d8986', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7060eb6f-8b75-4dcd-b7ed-90b63b5d8986', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('40837e93-aef4-40d6-a619-0330eaa64ea6', $q$Experiments notebook$q$, $q$Rich-text protocol and results documentation with entry locking and timestamping for reproducibility and audit purposes.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('40837e93-aef4-40d6-a619-0330eaa64ea6', $q$Inventory and database module$q$, $q$Catalog samples, reagents, antibodies, cell lines, and equipment with custom metadata fields.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('40837e93-aef4-40d6-a619-0330eaa64ea6', $q$Electronic signatures$q$, $q$Sign off on experiment entries electronically to support compliance and accountability workflows.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('40837e93-aef4-40d6-a619-0330eaa64ea6', $q$Full audit logging$q$, $q$Detailed activity logs and version history track every change made to notebook entries.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('40837e93-aef4-40d6-a619-0330eaa64ea6', $q$Docker-based self-hosting$q$, $q$Straightforward containerized deployment lets institutions run eLabFTW on their own infrastructure.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('40837e93-aef4-40d6-a619-0330eaa64ea6', $q$Entry linking and tagging$q$, $q$Cross-link experiments and inventory items, and organize records with tags for fast retrieval.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('40837e93-aef4-40d6-a619-0330eaa64ea6', $q$Export and reporting$q$, $q$Export experiments and data for sharing, archival, or inclusion in publications and grant reports.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('40837e93-aef4-40d6-a619-0330eaa64ea6', $q$Multi-language interface$q$, $q$Community-translated interface supporting numerous languages beyond English.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('40837e93-aef4-40d6-a619-0330eaa64ea6', $q$Completely free and open source under the AGPL with no paywalled features$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('40837e93-aef4-40d6-a619-0330eaa64ea6', $q$Strong fit for labs with strict data-sovereignty or open-science requirements$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('40837e93-aef4-40d6-a619-0330eaa64ea6', $q$Combines both a notebook and an inventory/database system in one platform$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('40837e93-aef4-40d6-a619-0330eaa64ea6', $q$Optional PRO support and hosting tiers give institutions a path to professional support without forcing a paid license$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('40837e93-aef4-40d6-a619-0330eaa64ea6', $q$Self-hosting requires Docker and server administration knowledge if not using paid hosting$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('40837e93-aef4-40d6-a619-0330eaa64ea6', $q$Interface is more utilitarian than some polished commercial ELN competitors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('40837e93-aef4-40d6-a619-0330eaa64ea6', $q$Advanced compliance hosting (SecNumCloud) is priced at a level aimed at institutions, not individual labs$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('40837e93-aef4-40d6-a619-0330eaa64ea6', $q$Smaller company size than large commercial ELN vendors may mean slower feature rollout for niche requests$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('40837e93-aef4-40d6-a619-0330eaa64ea6', $q$Is eLabFTW really free?$q$, $q$Yes. eLabFTW is open source under the AGPL and can be self-hosted with the full feature set at no cost. Paid tiers only cover optional professional support and managed hosting.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('40837e93-aef4-40d6-a619-0330eaa64ea6', $q$Who created eLabFTW?$q$, $q$eLabFTW was created by Nicolas Carpi, a research engineer at the Institut Curie in Paris, who first released it around 2012 and later founded Deltablot SASU in 2019 to support it commercially.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('40837e93-aef4-40d6-a619-0330eaa64ea6', $q$What does PRO Support include?$q$, $q$PRO Support, starting from EUR 760 per year, gives self-hosting institutions direct access to Deltablot's engineering team for troubleshooting, upgrades, and configuration assistance.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('40837e93-aef4-40d6-a619-0330eaa64ea6', $q$What is PRO Hosting SecNumCloud?$q$, $q$It is a compliance-grade managed hosting tier, priced at EUR 6,985 per year, hosted exclusively in France with encryption at rest and infrastructure aligned to strict French and EU security and data-sovereignty standards.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('40837e93-aef4-40d6-a619-0330eaa64ea6', $q$What license does eLabFTW use?$q$, $q$eLabFTW is released under the GNU Affero General Public License (AGPL), which requires that modifications remain open source even when the software is offered as a network service.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('40837e93-aef4-40d6-a619-0330eaa64ea6', $q$Who typically uses eLabFTW?$q$, $q$Academic research groups, university core facilities, biotech and pharmaceutical R&D teams, and government research institutions that need auditable, reproducible documentation of experimental work.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('40837e93-aef4-40d6-a619-0330eaa64ea6', $q$Academic research documentation$q$, $q$University labs use eLabFTW to document experiments and maintain reproducible, timestamped records for publications and grant compliance.$q$, $q$Academic researchers and PhD students$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('40837e93-aef4-40d6-a619-0330eaa64ea6', $q$Sample and reagent inventory tracking$q$, $q$Core facilities catalog reagents, antibodies, and equipment with searchable metadata to reduce duplicate purchases and lost samples.$q$, $q$Lab managers and core facility staff$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('40837e93-aef4-40d6-a619-0330eaa64ea6', $q$Compliance-grade research hosting$q$, $q$Institutions with strict data-sovereignty requirements use PRO Hosting SecNumCloud to keep sensitive research data hosted within France under certified infrastructure.$q$, $q$Regulated research institutions$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('40837e93-aef4-40d6-a619-0330eaa64ea6', $q$Self-Hosted Community$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full experiments and inventory feature set","AGPL open-source license","Docker-based self-hosting","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('40837e93-aef4-40d6-a619-0330eaa64ea6', $q$PRO Support$q$, $q$From EUR 760/year$q$, $q$Annual$q$, NULL, $q$["Direct access to Deltablot engineering team","Upgrade and troubleshooting assistance","For self-hosted instances"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('40837e93-aef4-40d6-a619-0330eaa64ea6', $q$PRO Hosting$q$, $q$Custom (based on lab size)$q$, $q$Annual$q$, NULL, $q$["Fully managed cloud hosting","Automated backups","Custom domain name","Hosting in Europe, US, or Asia"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('40837e93-aef4-40d6-a619-0330eaa64ea6', $q$PRO Hosting SecNumCloud$q$, $q$EUR 6,985/year$q$, $q$Annual$q$, NULL, $q$["Compliance-grade hosting in France only","Encryption at rest","Aligned with SecNumCloud and ISO 27001 standards","All PRO Hosting features included"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('40837e93-aef4-40d6-a619-0330eaa64ea6', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$eLabFTW is a free, open-source electronic lab notebook that lets research teams document experiments, track samples and reagents, and keep a timestamped, auditable record of lab work. It was created by Nicolas Carpi at the Institut Curie in Paris and first released around 2012.$q$, $q$The project grew from a personal tool into one of the most widely used open-source ELNs in academic research, leading Carpi to found Deltablot SASU in 2019 to provide professional support and managed hosting around the free software.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('40837e93-aef4-40d6-a619-0330eaa64ea6', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform combines an experiments module, where researchers write rich-text protocols and results that can be locked and timestamped for reproducibility, with a database/inventory module for cataloging samples, reagents, and equipment using custom metadata fields. Entries can be cross-linked, tagged, and exported for sharing or archival.$q$, $q$eLabFTW supports electronic signatures, detailed audit logs, and version history to help labs meet compliance needs such as ISO 17025 or good laboratory practice. It is deployed via Docker for straightforward self-hosting and is released under the AGPL, ensuring the code stays open even when run as a hosted service.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('40837e93-aef4-40d6-a619-0330eaa64ea6', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The core software is completely free with no features behind a paywall; any lab that self-hosts eLabFTW gets the full feature set at no cost under the AGPL license.$q$, $q$Deltablot monetizes optional services: PRO Support starts from EUR 760 per year for direct engineering help with self-hosted instances, PRO Hosting offers fully managed cloud deployment in Europe, the US, or Asia at custom pricing, and PRO Hosting SecNumCloud, at EUR 6,985 per year, provides compliance-grade hosting exclusively in France for organizations with strict data-sovereignty needs.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('40837e93-aef4-40d6-a619-0330eaa64ea6', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('40837e93-aef4-40d6-a619-0330eaa64ea6', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('40837e93-aef4-40d6-a619-0330eaa64ea6', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('40837e93-aef4-40d6-a619-0330eaa64ea6', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('40837e93-aef4-40d6-a619-0330eaa64ea6', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1e765d41-8506-4bbb-8502-4b6b293c5c29', $q$AI avatar video generation$q$, $q$Converts scripts or documents into videos featuring lifelike AI avatars with synchronized lip movement and gestures.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1e765d41-8506-4bbb-8502-4b6b293c5c29', $q$80+ avatars and 75+ languages$q$, $q$A large library of avatars and languages with hundreds of accents supports multinational, localized training content.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1e765d41-8506-4bbb-8502-4b6b293c5c29', $q$Interactive video elements$q$, $q$Branching paths, clickable buttons, hotspots, and text- or image-based quizzes can be embedded directly in the video player.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1e765d41-8506-4bbb-8502-4b6b293c5c29', $q$Voice cloning and Selfie Avatars$q$, $q$Paid add-ons let organizations create a cloned voice or a personal avatar likeness for more customized presenter videos.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1e765d41-8506-4bbb-8502-4b6b293c5c29', $q$Custom branding and templates$q$, $q$Upload custom images, fonts, and background music, and reuse custom templates across video projects.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1e765d41-8506-4bbb-8502-4b6b293c5c29', $q$SCORM export and LMS integration$q$, $q$Enterprise plan supports SCORM packaging for direct import into learning management systems.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1e765d41-8506-4bbb-8502-4b6b293c5c29', $q$4K Ultra HD export$q$, $q$Team and Enterprise plans support exporting finished videos in 4K Ultra HD resolution.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1e765d41-8506-4bbb-8502-4b6b293c5c29', $q$Collaboration workspaces$q$, $q$Team and Enterprise plans include multi-editor and guest workspace collaboration tools.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1e765d41-8506-4bbb-8502-4b6b293c5c29', $q$Purpose-built for corporate training with interactive quizzes and SCORM export, not just generic AI video$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1e765d41-8506-4bbb-8502-4b6b293c5c29', $q$Free plan and moderately priced Creator tier make it accessible for smaller teams to trial$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1e765d41-8506-4bbb-8502-4b6b293c5c29', $q$Large avatar and language library supports localized training at scale$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1e765d41-8506-4bbb-8502-4b6b293c5c29', $q$Backing from Panopto adds enterprise video infrastructure and integration options$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1e765d41-8506-4bbb-8502-4b6b293c5c29', $q$Monthly video-minute limits mean heavy users can face additional per-minute charges$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1e765d41-8506-4bbb-8502-4b6b293c5c29', $q$Voice cloning and custom avatars are paid add-ons rather than included features$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1e765d41-8506-4bbb-8502-4b6b293c5c29', $q$AI avatars, while broad in selection, can still look synthetic compared to real filmed video$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1e765d41-8506-4bbb-8502-4b6b293c5c29', $q$Enterprise pricing is not published and requires a custom sales conversation$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1e765d41-8506-4bbb-8502-4b6b293c5c29', $q$Is Elai free to use?$q$, $q$Elai offers a free plan that includes one minute of video generation with no credit card required, letting users try the avatar, voice, and language library before subscribing.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1e765d41-8506-4bbb-8502-4b6b293c5c29', $q$How much does Elai cost?$q$, $q$The Creator plan starts at $29/month ($23/month billed annually) for 15 minutes of video per month. The Team plan is $125/month ($100/month billed annually) for 50 minutes and multi-user collaboration. Enterprise pricing is custom.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1e765d41-8506-4bbb-8502-4b6b293c5c29', $q$Who owns Elai now?$q$, $q$Elai was acquired by Panopto, an enterprise video platform company, in late 2024. It continues to operate under the Elai brand as part of Panopto's video ecosystem.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1e765d41-8506-4bbb-8502-4b6b293c5c29', $q$Can Elai create interactive training videos?$q$, $q$Yes, Elai supports branching video paths, clickable buttons, hotspots, and text- or image-based quizzes embedded directly in the video player, which is a core differentiator for training use cases.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1e765d41-8506-4bbb-8502-4b6b293c5c29', $q$Does Elai support voice cloning?$q$, $q$Voice cloning is available as a paid add-on for $200/year, or included in limited quantities on the Team and Enterprise plans.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1e765d41-8506-4bbb-8502-4b6b293c5c29', $q$How many languages does Elai support?$q$, $q$Elai supports more than 75 languages with over 450 regional accents across its AI avatars and voices.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1e765d41-8506-4bbb-8502-4b6b293c5c29', $q$Corporate onboarding and training$q$, $q$HR and L&D teams create standardized onboarding and compliance training videos without filming or hiring voice actors.$q$, $q$Corporate learning and development teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1e765d41-8506-4bbb-8502-4b6b293c5c29', $q$Multilingual e-learning localization$q$, $q$Global organizations use Elai's language and accent library to localize the same training content for dozens of markets quickly.$q$, $q$Multinational enterprises and e-learning teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1e765d41-8506-4bbb-8502-4b6b293c5c29', $q$Interactive assessment-embedded video$q$, $q$Training designers embed quizzes and branching decisions directly inside videos to make learning content measurable and engaging.$q$, $q$Instructional designers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1e765d41-8506-4bbb-8502-4b6b293c5c29', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["1 minute of video","80+ AI avatars and 75+ languages","No credit card required"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1e765d41-8506-4bbb-8502-4b6b293c5c29', $q$Creator$q$, $q$$29/month ($23/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["15 minutes of video per month","Full HD video export","Complete avatar, voice, and language library","1 user"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1e765d41-8506-4bbb-8502-4b6b293c5c29', $q$Team$q$, $q$$125/month ($100/month billed annually, $1,200/year)$q$, $q$Monthly or annual$q$, NULL, $q$["50 minutes of video per month","3 editors + 3 guests","4K Ultra HD export","100+ premium voices, custom branding, and workspace collaboration"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1e765d41-8506-4bbb-8502-4b6b293c5c29', $q$Enterprise$q$, $q$Custom$q$, $q$Annual$q$, NULL, $q$["Unlimited users and custom minute allocation","SSO and SOC 2 compliance","SCORM export and Panopto integration","Dedicated onboarding and premium support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1e765d41-8506-4bbb-8502-4b6b293c5c29', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Elai is an AI video generation platform that converts scripts, documents, or slides into presenter-led videos using AI avatars and synthetic voices, with a particular focus on corporate training and e-learning content rather than general marketing video.$q$, $q$Co-founded in 2021 by Vitalii Romanchenko and Alex Uspenskyi, Elai launched its flagship Builder product in 2022 and grew to serve more than 2,000 organizations before being acquired by enterprise video platform Panopto in late 2024.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1e765d41-8506-4bbb-8502-4b6b293c5c29', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Users write or upload a script and choose from 80 or more AI avatars and over 75 languages with more than 450 accents to generate a fully voiced, lip-synced video automatically. Videos can be branded with custom images, fonts, templates, and background music.$q$, $q$A standout capability is interactive video: branching narratives, clickable buttons, hotspots, and text- or image-based quizzes can be embedded directly inside the video player, letting training teams build assessments into the video itself. SCORM export supports direct integration with learning management systems.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1e765d41-8506-4bbb-8502-4b6b293c5c29', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Elai offers a free plan with one minute of video and no credit card required, followed by the Creator plan at $29/month ($23/month billed annually) for 15 minutes of video per month, and the Team plan at $125/month ($100/month billed annually, $1,200/year) for 50 minutes and three editor and guest workspaces.$q$, $q$Enterprise pricing is custom and includes unlimited users, SSO, SCORM export, and Panopto integration. Add-ons across paid plans include a Studio Avatar ($500/year), Selfie Avatar ($199/year), voice cloning ($200/year), and extra video minutes at $2 per minute.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1e765d41-8506-4bbb-8502-4b6b293c5c29', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1e765d41-8506-4bbb-8502-4b6b293c5c29', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1e765d41-8506-4bbb-8502-4b6b293c5c29', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1e765d41-8506-4bbb-8502-4b6b293c5c29', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1e765d41-8506-4bbb-8502-4b6b293c5c29', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1e765d41-8506-4bbb-8502-4b6b293c5c29', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0884da11-18e8-4de8-bdba-1469c9e43607', $q$Transactional Email API$q$, $q$REST API for sending account notifications, receipts, and other system-triggered emails with templated merge fields and attachments.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0884da11-18e8-4de8-bdba-1469c9e43607', $q$SMTP Relay$q$, $q$Drop-in SMTP relay endpoint that lets developers redirect existing mail server configurations to Elastic Email without code changes.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0884da11-18e8-4de8-bdba-1469c9e43607', $q$Drag-and-Drop Email Designer$q$, $q$Visual campaign builder for creating newsletters and promotional emails without writing HTML.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0884da11-18e8-4de8-bdba-1469c9e43607', $q$Marketing Automation$q$, $q$Behavior-triggered workflows and drip sequences for nurturing subscribers over time.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0884da11-18e8-4de8-bdba-1469c9e43607', $q$Deliverability and Reputation Tools$q$, $q$SPF, DKIM, and DMARC authentication support along with sender reputation monitoring and dedicated IP options.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0884da11-18e8-4de8-bdba-1469c9e43607', $q$Real-Time Event Webhooks$q$, $q$Webhook and dashboard reporting for opens, clicks, bounces, complaints, and unsubscribes.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0884da11-18e8-4de8-bdba-1469c9e43607', $q$List Management and Segmentation$q$, $q$Contact list tools with custom fields, suppression lists, and audience segmentation for targeted sends.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0884da11-18e8-4de8-bdba-1469c9e43607', $q$Reseller and Sub-Account Support$q$, $q$Pro-tier white-label and sub-account management features aimed at agencies managing multiple clients.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0884da11-18e8-4de8-bdba-1469c9e43607', $q$Combines transactional and marketing email in one account, avoiding the need for separate vendors and reputation pools.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0884da11-18e8-4de8-bdba-1469c9e43607', $q$Pricing is generally lower than comparable developer-focused competitors like SendGrid, Mailgun, and Postmark.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0884da11-18e8-4de8-bdba-1469c9e43607', $q$Free tier and self-serve signup make it easy to test integrations before committing to a paid plan.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0884da11-18e8-4de8-bdba-1469c9e43607', $q$Supports both a full REST API and a standard SMTP relay, easing migration from self-hosted mail servers.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0884da11-18e8-4de8-bdba-1469c9e43607', $q$Deliverability reputation can be inconsistent on shared IP pools compared to specialist transactional providers like Postmark.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0884da11-18e8-4de8-bdba-1469c9e43607', $q$Marketing automation and design tools are less sophisticated than dedicated marketing platforms like Mailchimp or Klaviyo.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0884da11-18e8-4de8-bdba-1469c9e43607', $q$Customer support response times can lag on lower-tier plans without a paid support add-on.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0884da11-18e8-4de8-bdba-1469c9e43607', $q$Documentation and UI polish trail some larger, venture-backed competitors.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0884da11-18e8-4de8-bdba-1469c9e43607', $q$Is Elastic Email free to use?$q$, $q$Yes, Elastic Email offers a free plan that includes a limited monthly email volume and contact count, suitable for testing integrations before upgrading to a paid tier.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0884da11-18e8-4de8-bdba-1469c9e43607', $q$Does Elastic Email support both SMTP and API sending?$q$, $q$Yes, Elastic Email provides both a REST API and a standard SMTP relay endpoint, so developers can integrate however best fits their existing stack.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0884da11-18e8-4de8-bdba-1469c9e43607', $q$How does Elastic Email pricing work?$q$, $q$Pricing is split across an Email API line, billed by monthly email volume starting at $19/month, and an Email Marketing line, billed by contact list size starting around $29/month.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0884da11-18e8-4de8-bdba-1469c9e43607', $q$How does Elastic Email compare to SendGrid or Mailgun?$q$, $q$Elastic Email generally undercuts SendGrid and Mailgun on price while offering a comparable API and SMTP feature set, though its deliverability tooling and documentation are less extensive than those larger, venture-backed platforms.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0884da11-18e8-4de8-bdba-1469c9e43607', $q$Can agencies manage multiple clients on Elastic Email?$q$, $q$Yes, the Pro plan includes reseller capabilities and sub-account management designed for agencies handling email sending on behalf of multiple clients.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0884da11-18e8-4de8-bdba-1469c9e43607', $q$Who founded Elastic Email and when?$q$, $q$Elastic Email was founded in 2010 by a small team of Polish and Canadian engineers and remains an independent, privately held company with offices in Vancouver, Canada and Szczecin, Poland.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0884da11-18e8-4de8-bdba-1469c9e43607', $q$Transactional Email for SaaS Products$q$, $q$Developers integrate the API or SMTP relay to send account notifications, password resets, and receipts reliably at scale.$q$, $q$Software developers and SaaS engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0884da11-18e8-4de8-bdba-1469c9e43607', $q$Combined Transactional and Marketing Email$q$, $q$Businesses that need both system emails and periodic newsletters manage both from a single account and reputation pool.$q$, $q$Small and mid-sized business owners and marketers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0884da11-18e8-4de8-bdba-1469c9e43607', $q$White-Label Email Delivery for Agencies$q$, $q$Agencies use sub-accounts and reseller features to manage email sending on behalf of multiple clients under one master account.$q$, $q$Digital marketing and email agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0884da11-18e8-4de8-bdba-1469c9e43607', $q$Free$q$, $q$$0$q$, $q$monthly$q$, NULL, $q$["Up to 1,000 contacts and roughly 3,000 emails per month","Basic email API and SMTP relay","Email designer","Suppression list management"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0884da11-18e8-4de8-bdba-1469c9e43607', $q$Starter (Email API)$q$, $q$$19$q$, $q$monthly$q$, NULL, $q$["Up to 50,000 emails per month","Tracking and analytics","Standard customer support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0884da11-18e8-4de8-bdba-1469c9e43607', $q$Pro (Email API)$q$, $q$$49$q$, $q$monthly$q$, NULL, $q$["Up to 50,000 emails per month","Inbound email processing and webhooks","Reseller capabilities and sub-accounts","Custom reverse DNS"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0884da11-18e8-4de8-bdba-1469c9e43607', $q$Email Marketing$q$, $q$From $29$q$, $q$monthly$q$, NULL, $q$["Up to 2,500 contacts and roughly 37,500 emails per month","Drag-and-drop campaign builder","Marketing automation workflows","Contact segmentation"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0884da11-18e8-4de8-bdba-1469c9e43607', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Elastic Email is a combined transactional email API, SMTP relay, and email marketing platform designed for developers and small-to-midsize marketing teams. It lets a single account send both system-triggered messages, like password resets and receipts, and bulk marketing campaigns through the same sending infrastructure and reputation pool.$q$, $q$Founded in 2010 by Polish and Canadian engineers, the company has grown as an independent, self-funded business with offices in Vancouver, Canada and Szczecin, Poland, serving roughly 30,000 customers worldwide.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0884da11-18e8-4de8-bdba-1469c9e43607', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core features include a REST API and SMTP relay for transactional sending, a drag-and-drop email designer for marketing campaigns, contact list segmentation, marketing automation workflows, and webhook-based event tracking for opens, clicks, bounces, and complaints.$q$, $q$Deliverability tooling covers SPF, DKIM, and DMARC domain authentication, dedicated IP address options, sender reputation monitoring, and suppression list management, all aimed at helping senders maintain inbox placement at scale.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0884da11-18e8-4de8-bdba-1469c9e43607', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Elastic Email offers a free tier for low-volume testing, then splits paid pricing across two product lines: the Email API line starting at $19/month for 50,000 emails and scaling to plans supporting up to 10 million emails per month, and the Email Marketing line starting at roughly $29/month based on contact list size.$q$, $q$Add-ons include dedicated private IP addresses and premium support, and pricing is generally positioned below comparable developer-focused competitors like SendGrid, Mailgun, and Postmark.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0884da11-18e8-4de8-bdba-1469c9e43607', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0884da11-18e8-4de8-bdba-1469c9e43607', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0884da11-18e8-4de8-bdba-1469c9e43607', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0884da11-18e8-4de8-bdba-1469c9e43607', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0884da11-18e8-4de8-bdba-1469c9e43607', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0884da11-18e8-4de8-bdba-1469c9e43607', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f64e5322-805e-4448-852f-2b182baf140a', $q$Distributed Full-Text Search$q$, $q$Sharded, replicated indices built on Apache Lucene deliver near real-time full-text search with configurable relevance scoring across large datasets.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f64e5322-805e-4448-852f-2b182baf140a', $q$Powerful Aggregations$q$, $q$A rich aggregation framework supports analytics queries like metrics, histograms, and bucketing directly within the search engine.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f64e5322-805e-4448-852f-2b182baf140a', $q$Vector Search for AI$q$, $q$Dense vector fields and approximate nearest-neighbor search enable semantic search and retrieval-augmented generation use cases.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f64e5322-805e-4448-852f-2b182baf140a', $q$ELK Stack Integration$q$, $q$Native integration with Logstash and Beats for data ingestion and Kibana for visualization and dashboarding.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f64e5322-805e-4448-852f-2b182baf140a', $q$Elastic Observability$q$, $q$Purpose-built solution for centralized log aggregation, metrics monitoring, and application performance monitoring.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f64e5322-805e-4448-852f-2b182baf140a', $q$Elastic Security (SIEM)$q$, $q$Security information and event management capabilities built on top of the same search and analytics engine.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f64e5322-805e-4448-852f-2b182baf140a', $q$Elastic Cloud$q$, $q$Fully managed hosting service, originally built from the 2015 acquisition of Found, offering resource-based and serverless pricing tiers.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f64e5322-805e-4448-852f-2b182baf140a', $q$Flexible Licensing$q$, $q$Choice of the Elastic License, Server Side Public License, or, since 2024, the AGPL open-source license for self-managed deployments.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f64e5322-805e-4448-852f-2b182baf140a', $q$Highly scalable, distributed architecture handles massive datasets and high query volumes across industries.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f64e5322-805e-4448-852f-2b182baf140a', $q$Broad ecosystem of client libraries, plugins, and integrations, backed by a large and active community.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f64e5322-805e-4448-852f-2b182baf140a', $q$Combined search, observability, and security solutions reduce the need for separate specialized tools.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f64e5322-805e-4448-852f-2b182baf140a', $q$Return to AGPL licensing in 2024 restored a recognized open-source option after the 2021 SSPL/Elastic License controversy.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f64e5322-805e-4448-852f-2b182baf140a', $q$Operating and tuning a production Elasticsearch cluster requires significant expertise in shard management, memory sizing, and node scaling.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f64e5322-805e-4448-852f-2b182baf140a', $q$Elastic Cloud production costs can scale into the tens of thousands of dollars per month for large or security-focused deployments.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f64e5322-805e-4448-852f-2b182baf140a', $q$The 2021 relicensing away from Apache 2.0 caused lasting distrust among parts of the open-source community and drove the creation of the competing OpenSearch fork.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f64e5322-805e-4448-852f-2b182baf140a', $q$Advanced features like machine learning and certain security capabilities remain behind paid subscription tiers rather than the free license.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f64e5322-805e-4448-852f-2b182baf140a', $q$Is Elasticsearch free to use?$q$, $q$Yes, Elasticsearch can be self-hosted for free under a choice of licenses, including the AGPL open-source license reintroduced in August 2024; Elastic monetizes primarily through paid Elastic Cloud hosting and premium feature tiers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f64e5322-805e-4448-852f-2b182baf140a', $q$What is the difference between Elasticsearch and the ELK stack?$q$, $q$Elasticsearch is the search and analytics engine itself, while the ELK stack refers to Elasticsearch combined with Logstash for data ingestion and Kibana for visualization, often extended with Beats for lightweight data shipping.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f64e5322-805e-4448-852f-2b182baf140a', $q$Why did Elasticsearch change its license in 2021?$q$, $q$Elastic moved Elasticsearch and Kibana from Apache 2.0 to a dual Server Side Public License and Elastic License in January 2021, citing concerns that cloud providers like AWS were offering the software as a service without adequate collaboration or revenue sharing.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f64e5322-805e-4448-852f-2b182baf140a', $q$Did Elasticsearch become open source again?$q$, $q$Yes, in August 2024 Elastic added the AGPL as a third licensing option starting with version 8.16.0, making Elasticsearch and Kibana available under a recognized open-source license again alongside the existing source-available options.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f64e5322-805e-4448-852f-2b182baf140a', $q$What is the main open-source alternative to Elasticsearch?$q$, $q$OpenSearch, an Apache 2.0-licensed fork created by AWS and now governed under the Linux Foundation, is the most direct open-source alternative that emerged in response to Elastic's 2021 relicensing.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f64e5322-805e-4448-852f-2b182baf140a', $q$Who created Elasticsearch?$q$, $q$Shay Banon created Elasticsearch, releasing the first version in February 2010 as a distributed successor to his earlier Compass search server; he later co-founded Elastic N.V. in 2012 with Uri Boness, Simon Willnauer, and Steven Schuurman.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f64e5322-805e-4448-852f-2b182baf140a', $q$Enterprise and Application Search$q$, $q$Developers embed Elasticsearch to power full-text search, filtering, and relevance-ranked results within websites and applications.$q$, $q$Backend and platform engineers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f64e5322-805e-4448-852f-2b182baf140a', $q$Centralized Log Analytics and Observability$q$, $q$DevOps and SRE teams use the ELK stack to aggregate, search, and visualize logs and metrics across distributed infrastructure.$q$, $q$DevOps and site reliability engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f64e5322-805e-4448-852f-2b182baf140a', $q$Security Information and Event Management$q$, $q$Security teams use Elastic Security, built on Elasticsearch, as a SIEM platform for threat detection and incident investigation.$q$, $q$Security operations (SOC) teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f64e5322-805e-4448-852f-2b182baf140a', $q$Self-Managed (Free)$q$, $q$$0$q$, $q$n/a$q$, NULL, $q$["Self-hosted deployment under Elastic License, SSPL, or AGPL","Core search, indexing, and aggregation capabilities","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f64e5322-805e-4448-852f-2b182baf140a', $q$Elastic Cloud Standard$q$, $q$From ~$95/month$q$, $q$monthly$q$, NULL, $q$["Managed hosting on Elastic Cloud","Core logging, search, and basic security","Scales with data volume and node size"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f64e5322-805e-4448-852f-2b182baf140a', $q$Elastic Cloud Gold$q$, $q$From ~$114/month$q$, $q$monthly$q$, NULL, $q$["Adds support features and advanced capabilities","Available on Elastic Cloud Hosted"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f64e5322-805e-4448-852f-2b182baf140a', $q$Elastic Cloud Platinum$q$, $q$From ~$131/month$q$, $q$monthly$q$, NULL, $q$["Full SIEM and premium security features","Machine learning capabilities"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f64e5322-805e-4448-852f-2b182baf140a', $q$Elastic Cloud Enterprise$q$, $q$From ~$184/month$q$, $q$monthly$q$, NULL, $q$["Enterprise-grade security and support","Highest tier of managed features and SLAs"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f64e5322-805e-4448-852f-2b182baf140a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Elasticsearch is a distributed search and analytics engine built on Apache Lucene, offering a JSON REST API for full-text search, structured queries, aggregations, and vector similarity search. It forms the core of the Elastic Stack, alongside Logstash for data ingestion and Kibana for visualization.$q$, $q$Originally released in February 2010 by Shay Banon as a successor to his earlier Compass search server, Elasticsearch became the foundation of Elastic N.V., a company founded in 2012 that went public on the NYSE under the ticker ESTC in 2018.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f64e5322-805e-4448-852f-2b182baf140a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core capabilities include horizontally scalable, sharded indices, near real-time full-text search with relevance scoring, powerful aggregation queries for analytics, geospatial search, and dense vector fields for semantic and AI-driven search.$q$, $q$The broader Elastic Stack adds Kibana for dashboards and visualization, Logstash and Beats for data ingestion, and dedicated solution layers for observability (logs, metrics, APM) and security (SIEM, endpoint protection).$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f64e5322-805e-4448-852f-2b182baf140a', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Elasticsearch is free and open source to self-host, currently offered under a choice of the Elastic License, the Server Side Public License, or, since August 2024, the AGPL, after a widely discussed 2021 relicensing away from Apache 2.0 that prompted AWS to create the competing OpenSearch fork.$q$, $q$Elastic monetizes primarily through Elastic Cloud, its managed hosting service, with resource-based tiers historically named Standard, Gold, Platinum, and Enterprise, plus newer serverless, consumption-based pricing options billed per gigabyte ingested and stored.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f64e5322-805e-4448-852f-2b182baf140a', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f64e5322-805e-4448-852f-2b182baf140a', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f64e5322-805e-4448-852f-2b182baf140a', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f64e5322-805e-4448-852f-2b182baf140a', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f64e5322-805e-4448-852f-2b182baf140a', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f64e5322-805e-4448-852f-2b182baf140a', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a0ebe08-e4d6-46da-a624-6b276c676577', $q$End-to-End Encryption$q$, $q$Olm and Megolm cryptographic ratchets, derived from the Double Ratchet Algorithm, secure one-to-one and group conversations by default in private rooms.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a0ebe08-e4d6-46da-a624-6b276c676577', $q$Federated, Decentralized Architecture$q$, $q$Built on the open Matrix protocol, allowing organizations to self-host or connect across independently operated servers rather than depending on one central provider.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a0ebe08-e4d6-46da-a624-6b276c676577', $q$Self-Hosting via Synapse or Dendrite$q$, $q$Organizations can run their own homeserver using the reference Synapse implementation or the lighter-weight Dendrite server for full control over data residency.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a0ebe08-e4d6-46da-a624-6b276c676577', $q$Cross-Platform Clients$q$, $q$Native apps for web, Windows, macOS, Linux, iOS, and Android, all built against the shared open Matrix Client-Server API.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a0ebe08-e4d6-46da-a624-6b276c676577', $q$Element Call$q$, $q$Integrated WebRTC-based voice and video conferencing built directly into the messaging client.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a0ebe08-e4d6-46da-a624-6b276c676577', $q$Enterprise Identity and Compliance$q$, $q$LDAP/Active Directory and SSO authentication, data retention and export policies, and audit tooling available on Enterprise and Sovereign tiers.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a0ebe08-e4d6-46da-a624-6b276c676577', $q$Air-Gapped Sovereign Deployment$q$, $q$A dedicated Sovereign tier supports fully isolated, internet-free deployments for government and defense environments.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a0ebe08-e4d6-46da-a624-6b276c676577', $q$Bridging to Other Platforms$q$, $q$Optional bridges connect Matrix rooms to other messaging networks such as Slack, Discord, and IRC, extending interoperability beyond the Matrix ecosystem.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7a0ebe08-e4d6-46da-a624-6b276c676577', $q$Fully open source under the AGPL with no artificial caps on users, messages, or core features, even on the free self-hosted tier.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7a0ebe08-e4d6-46da-a624-6b276c676577', $q$Decentralized, federated architecture gives organizations full control over data residency, unlike single-vendor centralized platforms.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7a0ebe08-e4d6-46da-a624-6b276c676577', $q$End-to-end encryption is enabled by default in private rooms, backed by a well-regarded cryptographic protocol design.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7a0ebe08-e4d6-46da-a624-6b276c676577', $q$Strong track record with government and defense customers, including deployments in France and Germany, validating its security posture.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7a0ebe08-e4d6-46da-a624-6b276c676577', $q$Self-hosting a Synapse homeserver requires meaningful technical expertise and ongoing infrastructure maintenance.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7a0ebe08-e4d6-46da-a624-6b276c676577', $q$Enterprise and Sovereign tier pricing is not published and requires contacting sales, complicating budget comparisons against competitors.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7a0ebe08-e4d6-46da-a624-6b276c676577', $q$The federated architecture and richer feature set can feel more complex than simpler, purely consumer-focused apps like Signal.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7a0ebe08-e4d6-46da-a624-6b276c676577', $q$Some advanced enterprise features, such as SLAs and directory integration, are reserved for paid tiers rather than the free Community edition.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7a0ebe08-e4d6-46da-a624-6b276c676577', $q$Is Element free to use?$q$, $q$Yes, Element's Community edition is free and open source under the AGPL, supporting self-hosted deployments of up to about 100 users with the full feature set and no artificial limits.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7a0ebe08-e4d6-46da-a624-6b276c676577', $q$What is the Matrix protocol and how does it relate to Element?$q$, $q$Matrix is an open standard for decentralized, end-to-end encrypted real-time communication; Element is the flagship client and primary commercial sponsor built on top of it, though anyone can build alternative Matrix clients or homeservers.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7a0ebe08-e4d6-46da-a624-6b276c676577', $q$Can I self-host Element?$q$, $q$Yes, organizations can self-host their own Matrix homeserver using Synapse, the reference implementation maintained by Element, or Dendrite, a lighter-weight alternative, giving full control over data storage and retention.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7a0ebe08-e4d6-46da-a624-6b276c676577', $q$Was Element previously called Riot or Vector?$q$, $q$Yes, the app launched as Vector in 2016, was renamed Riot later that year, and was rebranded to Element in 2019 along with the parent company.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7a0ebe08-e4d6-46da-a624-6b276c676577', $q$Does Element support end-to-end encryption?$q$, $q$Yes, Element enables end-to-end encryption by default in private rooms using the Olm and Megolm cryptographic ratchets, based on the Double Ratchet Algorithm also used by Signal.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7a0ebe08-e4d6-46da-a624-6b276c676577', $q$How much does Element Enterprise cost?$q$, $q$Element's Enterprise and Sovereign tiers are priced per seat per month on a custom basis available on request; the company has previously published reference pricing around $3 to $4 per monthly active user for its Element Matrix Services hosting product.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7a0ebe08-e4d6-46da-a624-6b276c676577', $q$Self-Hosted Team Chat$q$, $q$Organizations run their own Synapse homeserver to replace Slack or Teams with a fully self-controlled, encrypted messaging platform.$q$, $q$IT teams and privacy-focused organizations$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7a0ebe08-e4d6-46da-a624-6b276c676577', $q$Sovereign Government Communications$q$, $q$Government agencies and defense organizations deploy Element's Sovereign tier for air-gapped, high-security internal messaging.$q$, $q$Government, defense, and public-sector agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7a0ebe08-e4d6-46da-a624-6b276c676577', $q$Cross-Organization Federated Messaging$q$, $q$Businesses and communities use Matrix's federation to communicate across independently hosted servers without relying on a single vendor.$q$, $q$Cross-organization teams and open-source communities$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7a0ebe08-e4d6-46da-a624-6b276c676577', $q$Community$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["Self-hosted deployment, up to ~100 users","Open source under AGPL","Synapse Community edition homeserver","Element Call included"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7a0ebe08-e4d6-46da-a624-6b276c676577', $q$Enterprise$q$, $q$Custom (per seat/month)$q$, $q$monthly$q$, NULL, $q$["Element Cloud or on-premise, from ~100 users","Synapse Pro homeserver with dynamic scaling","LDAP/AD and SSO authentication","Data retention, export, and audit tooling","SLA-backed support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7a0ebe08-e4d6-46da-a624-6b276c676577', $q$Sovereign$q$, $q$Custom (per deployment)$q$, $q$custom$q$, NULL, $q$["All Enterprise features","Fully air-gapped, internet-free operation","Dedicated mobile push gateway","Isolated, high-side instance support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7a0ebe08-e4d6-46da-a624-6b276c676577', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Element is an open-source messaging and collaboration client built on the Matrix protocol, a decentralized, federated standard for real-time, end-to-end encrypted communication. Users can self-host their own Matrix homeserver or rely on public and private servers that interoperate with one another.$q$, $q$Originally launched as Vector in 2016 and renamed Riot later that year, the app and its parent company were rebranded to Element in 2019. The company, New Vector Limited, spun out of Amdocs subsidiary Vector Creations Limited in 2017 and is now headquartered in Chiswick, London.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7a0ebe08-e4d6-46da-a624-6b276c676577', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Element supports one-to-one and group messaging, voice and video calls via Element Call, file sharing, threads, and end-to-end encryption by default using the Olm and Megolm cryptographic ratchets derived from the Double Ratchet Algorithm.$q$, $q$Clients are available for web, desktop (Windows, macOS, Linux), and mobile (iOS, Android), all built on the open Matrix Client-Server API, and the platform can be self-hosted using the Synapse or Dendrite homeserver implementations.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7a0ebe08-e4d6-46da-a624-6b276c676577', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Element's Community tier is free and fully open source under the AGPL, supporting self-hosted deployments of up to about 100 users with no artificial feature limits.$q$, $q$Paid Enterprise and Sovereign tiers, priced per seat per month on request, add managed hosting or on-premise deployment at scale, enhanced security, SSO and directory integration, SLAs, and, for Sovereign, fully air-gapped operation for government and defense use cases.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7a0ebe08-e4d6-46da-a624-6b276c676577', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7a0ebe08-e4d6-46da-a624-6b276c676577', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
