INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7a0ebe08-e4d6-46da-a624-6b276c676577', '381992fc-7997-449c-9c68-511f0dce4b99') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7a0ebe08-e4d6-46da-a624-6b276c676577', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
