-- Enrichment marathon batch: edX, egroupware, ejabberd, eLabFTW, Elai, Elastic Email, Elasticsearch, Element

-- ── edX ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$edX is an online learning marketplace offering courses, professional certificates, and degree programs from universities and companies worldwide, with free auditing and paid verified credentials.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (audit track); certificates from $50$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE($q$Large (owned by 2U, Inc., a private company)$q$, company_size),
  headquarters = COALESCE($q$Cambridge, Massachusetts, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$edX Review 2026: Courses, Certificates & Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$edX offers university-backed online courses and certificates. See 2026 pricing, free audit options, MicroMasters costs, features, and how it compares to Coursera.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$edX is an online learning platform that hosts massive open online courses (MOOCs), professional certificates, MicroMasters programs, and fully online degrees created in partnership with universities and companies such as Harvard, MIT, Columbia, IBM, and Google. It was founded in 2012 by Harvard University and the Massachusetts Institute of Technology as a joint nonprofit venture, with MIT's Anant Agarwal serving as founding CEO and MIT's Rafael Reif and researcher Piotr Mitros credited among its architects. The founding mission was to democratize access to elite university-level education by putting real course content from top institutions online, mostly for free, while also using the platform as a research tool for studying how people learn. In its first decade edX grew into one of the largest MOOC providers alongside Coursera and the now largely defunct Udacity, hosting thousands of courses across computer science, data science, business, engineering, humanities, and public health.

The nonprofit era ended in 2021, when edX's board sold the platform to 2U, Inc., a publicly traded online program management company, for $800 million in cash. The sale proceeds were used to establish a separate nonprofit, Axim Collaborative, to continue edX's original public-interest mission, while the edX brand, technology, and course catalog became a commercial 2U product. The acquisition proved financially troubled for 2U: burdened by debt and a slowing online-degree market, 2U filed for Chapter 11 bankruptcy in July 2024. The company emerged from bankruptcy later that year as a private business, eliminating more than $450 million in debt, and as of mid-2026 continues to operate edX as part of its portfolio alongside its other online-education services.

Technically, edX runs on the Open edX platform, an open-source learning management system originally built by edX itself and now maintained by a broader community of institutions and vendors under the Axim Collaborative and Open edX contributor ecosystem. Open edX is used not only to power edx.org but also by many universities and companies to run their own independent learning portals. On edx.org, learners browse a searchable catalog, watch video lectures, complete auto-graded and peer-graded assignments, participate in discussion forums, and track progress through a personal dashboard. Course content is produced by the partner university or company, not by edX itself, so quality and format vary by provider, though edX applies its own instructional-design standards during course review.

edX's pricing structure is transactional rather than subscription-based, which distinguishes it from Coursera Plus. Most courses can be audited entirely free, which unlocks video lectures and, in many cases, reading materials, but not graded assignments or a certificate. To receive a verified certificate carrying the institution's name and a shareable credential, learners pay per course, typically ranging from $50 to $300 depending on the subject and issuing institution. Stackable credentials cost more: Professional Certificate programs (multi-course sequences) generally run from about $299 to $1,500 or more, and MicroMasters programs, which can carry credit toward a full master's degree at partner universities, typically cost $600 to $1,500 for the full program. A smaller number of programs offer bundled annual access, with subscription-style options priced around $199 per year for unlimited certificates within a specific track. Since the 2U acquisition, some free-audit options have been scaled back on certain courses, and pricing has trended upward compared to edX's nonprofit years, a shift that has drawn criticism from higher-education commentators.

edX's target users span self-directed lifelong learners upgrading job skills, university students supplementing formal coursework, career changers pursuing professional certificates in fields like data analytics or cybersecurity, and organizations sourcing corporate training content. Its main competitors are Coursera, which offers a comparable university-partner model plus a flat-rate subscription; Udemy, which focuses on instructor-created courses at low fixed prices; LinkedIn Learning, aimed at corporate upskilling; and Khan Academy and FutureLearn for free and university-partnered learning respectively. edX differentiates itself through direct branding from prestigious universities on certificates, its open-source Open edX platform that other institutions can self-host, and deep integration with formal credit-bearing programs such as MicroMasters and MicroBachelors. Notable facts include edX's origins as a genuinely nonprofit, open-source project (a rarity among major MOOC platforms), its $800 million sale that remains one of the largest transactions in ed-tech history, and its status today as a for-profit product operating under a financially restructured parent company.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '5e95356b-e091-45fd-baab-10b9302b101c';

